ps.pstext:
if !IsFeatureImplemented(FEAT_SME2) && !IsFeatureImplemented(FEAT_SVE2p1) then
    EndOfDecode(Decode_UNDEF);
end;
let esize : integer{} = 8 << UInt(size);
let rsize : integer{} = 64;
let n : integer = UInt(Rn);
let m : integer = UInt(Rm);
let d0 : integer = UInt(Pd::'0');
let d1 : integer = UInt(Pd::'1');
let unsigned : boolean = TRUE;
let op : CmpOp = Cmp_GT;

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mask : bits(PL*2) = Ones{};
var operand1 : bits(rsize) = X{}(n);
let operand2 : bits(rsize) = X{}(m);
var result : bits(PL*2);
var last : boolean = TRUE;
let psize : integer{} = esize DIV 8;

let element2 : integer = if unsigned then UInt(operand2) else SInt(operand2);
for e = (elements*2)-1 downto 0 do
    let element1 : integer = if unsigned then UInt(operand1) else SInt(operand1);
    var cond : boolean;
    case op of
        when Cmp_GT => cond = (element1 >  element2);
        when Cmp_GE => cond = (element1 >= element2);
    end;

    last = last && cond;
    let pbit : bit = if last then '1' else '0';
    result[e*:psize] = ZeroExtend{psize}(pbit);
    operand1 = operand1 - 1;
end;

PSTATE.[N,Z,C,V] = PredTest{PL*2}(mask, result, esize);
P{PL}(d0) = result[PL-1:0];
P{PL}(d1) = result[PL*2-1:PL];
